-- Publish the bundled seed (U5) as the current hosted rule set (R11). Dev-signed; the production
-- rule set is published by a human with the real signing key. Re-runnable (upsert on version).
insert into public.rule_sets (version, payload, signature, is_current)
values (
  '1.0.0',
  '{"version":"1.0.0","services":{"youtube":{"matches":["*://*.youtube.com/*","*://m.youtube.com/*"],"surfaces":[{"id":"yt-shorts-redirect","label":"Shorts URL → watch page","action":"redirect","enabledByDefault":true,"redirect":{"urlMatch":"^/shorts(?:/([\\w-]+))?/?$","to":"/watch?v=$1","fallbackToPlaceholder":true}},{"id":"yt-sidebar","label":"Shorts in left guide + mini-guide","action":"hide","enabledByDefault":true,"selectors":["ytd-guide-entry-renderer:has(a[title=\"Shorts\"])","ytd-mini-guide-entry-renderer:has(a[title=\"Shorts\"])","a#endpoint[title=\"Shorts\"]","ytm-pivot-bar-item-renderer:has(a[href=\"/shorts\"])"]},{"id":"yt-home-shelf","label":"Shorts shelf on Home","action":"remove","enabledByDefault":true,"selectors":["ytd-reel-shelf-renderer","ytd-rich-section-renderer:has(ytd-rich-shelf-renderer[is-shorts])","ytm-reel-shelf-renderer"]},{"id":"yt-search","label":"Shorts shelf + results in Search","action":"remove","enabledByDefault":true,"selectors":["ytd-reel-shelf-renderer","ytd-video-renderer:has(a[href^=\"/shorts/\"])"]},{"id":"yt-subscriptions","label":"Shorts row in Subscriptions","action":"remove","enabledByDefault":true,"selectors":["ytd-reel-shelf-renderer"]},{"id":"yt-channel-tab","label":"Shorts tab on channel pages","action":"hide","enabledByDefault":true,"selectors":["yt-tab-shape[tab-title=\"Shorts\"]","tp-yt-paper-tab:has([href$=\"/shorts\"])"]},{"id":"yt-chips","label":"Shorts chip in pivot/chip bars","action":"hide","enabledByDefault":true,"selectors":["yt-chip-cloud-chip-renderer:has([title=\"Shorts\"])"]}]},"instagram":{"matches":["*://*.instagram.com/*"],"surfaces":[{"id":"ig-reels-url","label":"Direct Reels URL → placeholder","action":"placeholder","enabledByDefault":true,"urlMatch":"^/reels?(/|$)"},{"id":"ig-nav","label":"Reels nav (sidebar + bottom tab)","action":"hide","enabledByDefault":true,"selectors":["a[href=\"/reels/\"]","a:has(svg[aria-label=\"Reels\"])","[role=\"tablist\"] a[href*=\"/reels\"]"]},{"id":"ig-inline","label":"Reels embedded in Home feed","action":"remove","enabledByDefault":true,"selectors":["article:has(a[href^=\"/reel/\"])"]},{"id":"ig-explore-search","label":"Reel tiles in Explore + Search","action":"remove","enabledByDefault":true,"selectors":["a[href^=\"/reel/\"]:has(span[aria-label*=\"Clip\"])","a[href^=\"/reel/\"] > div > svg[aria-label=\"Clip\"]"]},{"id":"ig-suggested","label":"Suggested Reels","action":"remove","enabledByDefault":true,"selectors":["section:has(> a[href^=\"/reel/\"])"]},{"id":"ig-profile-tab","label":"Reels tab on profile grids","action":"hide","enabledByDefault":true,"selectors":["a[href$=\"/reels/\"]"]}]},"tiktok":{"matches":["*://*.tiktok.com/*"],"surfaces":[{"id":"tt-blocksite","label":"All of tiktok.com → placeholder","action":"blockSite","enabledByDefault":true}]},"facebook":{"matches":["*://*.facebook.com/*","*://m.facebook.com/*"],"surfaces":[{"id":"fb-reel-url","label":"Direct Reel URL → placeholder","action":"placeholder","enabledByDefault":true,"urlMatch":"^/reel/"},{"id":"fb-feed","label":"Reels in Home feed","action":"remove","enabledByDefault":true,"selectors":["div[role=\"article\"]:has(a[href*=\"/reel/\"])"]},{"id":"fb-left-menu","label":"Reels shortcut in left menu","action":"hide","enabledByDefault":true,"selectors":["a[aria-label=\"Reels\"]","li:has(> a[href*=\"/reel\"])"]},{"id":"fb-watch","label":"Reels inside Watch","action":"remove","enabledByDefault":true,"selectors":["div:has(> a[href*=\"/reel/\"])"]},{"id":"fb-search-groups","label":"Reels in Search + Groups","action":"remove","enabledByDefault":true,"selectors":["div[role=\"article\"]:has(a[href*=\"/reel/\"])"]},{"id":"fb-suggested","label":"Suggested + related Reels","action":"remove","enabledByDefault":true,"selectors":["div[role=\"article\"]:has(a[href*=\"/reel/\"])"]}]}}}'::jsonb,
  '{"kid":"still-dev-1","alg":"ed25519","value":"5eaa539051b2ea079a72ac3ec7d93a15347b7329d13dd3291b389a26ddd02721d45fc1cb11abc8fecfaa527a3a282f62b08824434757bf06c8aa0784ad67370a"}'::jsonb,
  true
)
on conflict (version) do update
  set payload = excluded.payload, signature = excluded.signature, is_current = true;
